namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly Lock _lock = new();

    private readonly List<Notification> _notifications = [];

    public NotificationService()
    {
        // Seed with initial fake data.
        _notifications.AddRange(
        [
            MakeNotification("Welcome to the notification center!"),
            MakeNotification("Your profile was updated successfully."),
            MakeNotification("New team member joined your project."),
        ]);
    }

    /// <summary>Returns all notifications available at this moment.</summary>
    public Task<List<Notification>> GetNotificationsAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_notifications.ToList());
        }
    }

    /// <summary>Returns only notifications with an Id greater than <paramref name="sinceId"/>.</summary>
    public Task<List<Notification>> GetNotificationsSinceAsync(int sinceId)
    {
        lock (_lock)
        {
            return Task.FromResult(
                _notifications.Where(n => n.Id > sinceId).ToList());
        }
    }

    /// <summary>Simulates new notifications arriving over time.</summary>
    public void SimulateIncoming()
    {
        var messages = new[]
        {
            "Deployment completed for staging.",
            "Disk usage exceeded 80% on server-4.",
            "Pull request #42 was merged.",
            "Scheduled backup finished.",
            "New comment on issue #17.",
            "CI pipeline succeeded for main branch.",
            "Security scan found 0 vulnerabilities.",
        };

        lock (_lock)
        {
            var message = messages[(_nextId - 1) % messages.Length];
            _notifications.Add(MakeNotification(message));
        }
    }

    private Notification MakeNotification(string message)
    {
        return new Notification(_nextId++, message, DateTime.UtcNow);
    }
}

@page "/notifications"
@rendermode InteractiveServer
@implements IDisposable
@inject NotificationService NotificationService

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@notifications.Count</span>
</h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications.OrderByDescending(x => x.Id))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>@n.Message</div>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> notifications = [];
    private CancellationTokenSource? _cts;

    [PersistentState]
    public List<Notification>? PersistedNotifications { get; set; }

    protected override async Task OnInitializedAsync()
    {
        // Restore from prerender state if available; otherwise load from service.
        if (PersistedNotifications is not null)
        {
            notifications = PersistedNotifications;
        }
        else
        {
            notifications = await NotificationService.GetNotificationsAsync();
            PersistedNotifications = notifications;
        }
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct);

            // Simulate a new notification arriving on the server side.
            NotificationService.SimulateIncoming();

            var latestId = notifications.Count > 0 ? notifications.Max(n => n.Id) : 0;
            var newer = await NotificationService.GetNotificationsSinceAsync(latestId);

            if (newer.Count > 0)
            {
                notifications.AddRange(newer);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

