+@page "/notifications"
+@rendermode InteractiveServer
+@implements IDisposable
+@inject NotificationService NotificationService
+
+<PageTitle>Notifications</PageTitle>
+
+<h1>
+    Notifications
+    <span class="badge bg-primary rounded-pill ms-2">@notifications.Count</span>
+</h1>
+
+@if (notifications.Count == 0)
+{
+    <p><em>No notifications yet.</em></p>
+}
+else
+{
+    <ul class="list-group">
+        @foreach (var n in notifications.OrderByDescending(x => x.Id))
+        {
+            <li class="list-group-item d-flex justify-content-between align-items-start">
+                <div>@n.Message</div>
+                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
+            </li>
+        }
+    </ul>
+}
+
+@code {
+    private List<Notification> notifications = [];
+    private CancellationTokenSource? _cts;
+
+    [PersistentState]
+    public List<Notification>? PersistedNotifications { get; set; }
+
+    protected override async Task OnInitializedAsync()
+    {
+        // Restore from prerender state if available; otherwise load from service.
+        if (PersistedNotifications is not null)
+        {
+            notifications = PersistedNotifications;
+        }
+        else
+        {
+            notifications = await NotificationService.GetNotificationsAsync();
+            PersistedNotifications = notifications;
+        }
+    }
+
+    protected override void OnAfterRender(bool firstRender)
+    {
+        if (firstRender)
+        {
+            _cts = new CancellationTokenSource();
+            _ = PollForNotificationsAsync(_cts.Token);
+        }
+    }
+
+    private async Task PollForNotificationsAsync(CancellationToken ct)
+    {
+        while (!ct.IsCancellationRequested)
+        {
+            await Task.Delay(TimeSpan.FromSeconds(5), ct);
+
+            // Simulate a new notification arriving on the server side.
+            NotificationService.SimulateIncoming();
+
+            var latestId = notifications.Count > 0 ? notifications.Max(n => n.Id) : 0;
+            var newer = await NotificationService.GetNotificationsSinceAsync(latestId);
+
+            if (newer.Count > 0)
+            {
+                notifications.AddRange(newer);
+                await InvokeAsync(StateHasChanged);
+            }
+        }
+    }
+
+    public void Dispose()
+    {
+        _cts?.Cancel();
+        _cts?.Dispose();
+    }
+}
+

